import{_ as a,o as s,c as i,a2 as t}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Super Admin","description":"","frontmatter":{},"headers":[],"relativePath":"en/features/super-admin.md","filePath":"en/features/super-admin.md"}'),n={name:"en/features/super-admin.md"};function l(o,e,r,c,d,p){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="super-admin" tabindex="-1">Super Admin <a class="header-anchor" href="#super-admin" aria-label="Permalink to &quot;Super Admin&quot;">​</a></h1><p>The <code>super_admin</code> role is created automatically by <code>clearance:install</code> and kept in sync with all <code>clearance-*</code> permissions.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install and make user ID 1 a super admin</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user=1</span></span></code></pre></div><p>See the <a href="/clearance-docs/en/guide/installation.html">Installation guide</a> and <a href="/clearance-docs/en/api/artisan-commands.html">Artisan commands reference</a> for the full installer flag list.</p><h2 id="gate-bypass-opt-in" tabindex="-1">Gate bypass (opt-in) <a class="header-anchor" href="#gate-bypass-opt-in" aria-label="Permalink to &quot;Gate bypass (opt-in)&quot;">​</a></h2><p><code>super_admin_gate_bypass</code> controls whether the <code>super_admin</code> role bypasses all Laravel <code>can()</code> / <code>Gate::allows()</code> / policy checks globally, via a <code>Gate::before()</code> hook. Default: <code>false</code>. The bypass is opt-in. To enable it:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;super_admin_gate_bypass&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">Application-wide, not panel-scoped</p><p>When enabled, any user holding <code>super_admin</code> skips <strong>all</strong> Gate checks application-wide - not only Clearance panel checks. This affects every <code>can()</code>, <code>Gate::allows()</code>, and policy check in your application, not just the ones Clearance defines. For a narrower scope, leave it off and grant permissions explicitly instead.</p></div><h2 id="alias-detection" tabindex="-1">Alias detection <a class="header-anchor" href="#alias-detection" aria-label="Permalink to &quot;Alias detection&quot;">​</a></h2><p>If your database already contains a role named <code>super_admin</code>, <code>superadmin</code>, <code>super-admin</code>, <code>root</code>, or <code>owner</code>, the installer detects it and prompts you interactively to promote it or create a separate <code>super_admin</code>. Use <code>--super-admin-role=NAME</code> to skip the prompt:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --super-admin-role=owner</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Promotion is non-destructive</p><p>Promotion renames the role in place - all existing <code>model_has_roles</code> assignments are preserved via the FK on <code>role_id</code>. No user loses their existing role assignment during promotion.</p></div><h2 id="panel-access-fine-grained-write-permissions" tabindex="-1">Panel Access &amp; Fine-grained write permissions <a class="header-anchor" href="#panel-access-fine-grained-write-permissions" aria-label="Permalink to &quot;Panel Access &amp; Fine-grained write permissions&quot;">​</a></h2><p>Navigate to <code>/clearance</code> after installation. Read access to the whole panel requires the <code>clearance-access</code> permission, checked via <code>can()</code>, never <code>hasRole()</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>Write operations on each section are gated by a dedicated, delegable permission - all created by <code>clearance:install</code> and assigned to <code>super_admin</code>:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Controls</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>Create / edit / delete permissions</td></tr><tr><td><code>clearance-roles-write</code></td><td>Create / edit / delete roles and their permission assignments</td></tr><tr><td><code>clearance-guards-write</code></td><td>Create / edit / delete guards</td></tr><tr><td><code>clearance-settings-write</code></td><td>Edit display metadata, icons, colors, default role</td></tr><tr><td><code>clearance-users-write</code></td><td>Assign / remove roles for a specific user</td></tr></tbody></table><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Grant a user write access to roles only:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-roles-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Granting narrow access</p><p>Combine <code>clearance-access</code> with exactly one <code>clearance-{section}-write</code> permission to hand a user (say, a team lead) write access to a single panel section - roles, for instance - without exposing settings, guards, or user management.</p></div><p>If a fine-grained permission row doesn&#39;t exist at all in the database (a legacy pre-seeding state), the check falls back to <code>clearance-access</code> for backwards compatibility. On any instance that has run <code>clearance:install</code>, this fallback never activates.</p><h2 id="reserved-clearance-permissions" tabindex="-1">Reserved <code>clearance-*</code> permissions <a class="header-anchor" href="#reserved-clearance-permissions" aria-label="Permalink to &quot;Reserved \`clearance-*\` permissions&quot;">​</a></h2><p><code>clearance-*</code> permissions are reserved: they cannot be created, renamed, deleted, or added to any role except through the package&#39;s own install flow - even by a <code>super_admin</code> actor for the <code>super_admin</code> role itself.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/clearance-docs/en/features/permissions.html">Permissions</a> - the general permission CRUD panel (excludes <code>clearance-*</code>).</li><li><a href="/clearance-docs/en/features/roles.html">Roles</a> - assigning <code>clearance-*-write</code> permissions to a custom role.</li><li><a href="/clearance-docs/en/guide/security.html">Security</a> - the full privilege-escalation and ceiling model.</li></ul>`,24)])])}const g=a(n,[["render",l]]);export{k as __pageData,g as default};
